class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] primeCount = new int[n];
        boolean[] isPrime = new boolean[100001];
        for (int i = 0; i <= 100000; i++) {
            isPrime[i] = true;
        }
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= 100000; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= 100000; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            primeCount[i] = isPrime[nums[i]] ? 1 : 0;
        }
        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + primeCount[i];
        }
        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int val = queries[i][1];
            int oldVal = nums[idx];
            nums[idx] = val;
            int newPrimeCount = isPrime[val] ? 1 : 0;
            int oldPrimeCount = isPrime[oldVal] ? 1 : 0;
            prefixSum[idx + 1] += newPrimeCount - oldPrimeCount;
            for (int j = idx + 2; j <= n; j++) {
                prefixSum[j] += newPrimeCount - oldPrimeCount;
            }
            int maxCount = 0;
            for (int k = 1; k < n; k++) {
                int leftCount = prefixSum[k];
                int rightCount = prefixSum[n] - prefixSum[k];
                maxCount = Math.max(maxCount, leftCount + rightCount);
            }
            result[i] = maxCount;
        }
        return result;
    }
}
